UPDATE watermark_control
SET last_loaded_timestamp = (
    SELECT MAX(last_modified)
    FROM IDENTIFIER('@{item().table_name}_snowflake')
)
WHERE table_name = '@{item().table_name}';

DECLARE 
    src_table STRING DEFAULT '@{item().table_name}_stage';
    tgt_table STRING DEFAULT '@{item().table_name}_snowflake';
    pk STRING DEFAULT '@{item().primary_key}';
    col_list STRING;
    upd_list STRING;
    merge_sql STRING;
BEGIN
    SELECT LISTAGG(column_name, ', ') 
    INTO :col_list
    FROM INFORMATION_SCHEMA.COLUMNS
    WHERE table_name = UPPER(:tgt_table);

    SELECT LISTAGG('t.' || column_name || ' = s.' || column_name, ', ')
    INTO :upd_list
    FROM INFORMATION_SCHEMA.COLUMNS
    WHERE table_name = UPPER(:tgt_table)
    AND column_name <> UPPER(:pk);

    merge_sql := '
        MERGE INTO ' || tgt_table || ' t
        USING ' || src_table || ' s
        ON t.' || pk || ' = s.' || pk || '
        WHEN MATCHED THEN UPDATE SET ' || upd_list || '
        WHEN NOT MATCHED THEN INSERT (' || col_list || ')
        VALUES (' || REPLACE(col_list, ',', ', s.') || ')
    ';

    EXECUTE IMMEDIATE merge_sql;
END;

DECLARE 
    src_table STRING DEFAULT '@{item().table_name}_snowflake';
    tgt_table STRING DEFAULT '@{item().table_name}_scd2';
    pk STRING DEFAULT '@{item().primary_key}';

    col_list STRING;
    compare_list STRING;
    insert_cols STRING;
    insert_vals STRING;
    expire_sql STRING;
    insert_sql STRING;

BEGIN
    -- Business column list (from source/bronze table)
    SELECT LISTAGG(column_name, ', ')
    INTO :col_list
    FROM INFORMATION_SCHEMA.COLUMNS
    WHERE table_name = UPPER(:src_table)
      AND column_name NOT IN ('EFFECTIVE_START_DATE','EFFECTIVE_END_DATE','IS_CURRENT');

    -- Change detection condition (datatype-safe)
    SELECT LISTAGG(
        'NVL(TO_VARCHAR(t.' || column_name || '),'''') <> NVL(TO_VARCHAR(s.' || column_name || '),'''')',
        ' OR '
    )
    INTO :compare_list
    FROM INFORMATION_SCHEMA.COLUMNS
    WHERE table_name = UPPER(:src_table)
      AND column_name NOT IN ('EFFECTIVE_START_DATE','EFFECTIVE_END_DATE','IS_CURRENT', UPPER(:pk));

    -- Insert columns and values
    insert_cols := col_list || ', effective_start_date, effective_end_date, is_current';

    insert_vals := REPLACE(col_list, ',', ', s.');
    insert_vals := 's.' || insert_vals || ', CURRENT_TIMESTAMP, NULL, TRUE';

    -- Step 1: Expire old records (only if changed)
    expire_sql := '
        UPDATE ' || tgt_table || ' t
        SET effective_end_date = CURRENT_TIMESTAMP,
            is_current = FALSE
        FROM ' || src_table || ' s
        WHERE t.' || pk || ' = s.' || pk || '
          AND t.is_current = TRUE
          AND (' || compare_list || ')
    ';

    -- Step 2: Insert new and changed records
    insert_sql := '
        INSERT INTO ' || tgt_table || ' (' || insert_cols || ')
        SELECT ' || insert_vals || '
        FROM ' || src_table || ' s
        LEFT JOIN ' || tgt_table || ' t
          ON s.' || pk || ' = t.' || pk || '
         AND t.is_current = TRUE
        WHERE t.' || pk || ' IS NULL
           OR (' || compare_list || ')
    ';

    EXECUTE IMMEDIATE expire_sql;
    EXECUTE IMMEDIATE insert_sql;

END;
